INSERT INTO goals (id, tenant_id, title, description, state, target_date, parent_goal_id, altitude, created_by_event_id) VALUES ('1093faf1-c415-5ea2-8801-4f75b7ee6205', '00000000-0000-0000-0000-000000000000', 'Ship conversation-AI module v1', 'Conversation-AI module taps into Gong/Chorus call recordings and surfaces deal risk signals. Q3 release.', 'active', '2027-01-01T13:11:52.017582+00:00', NULL, 'operational', '00000000-0000-7d24-8000-000034c17fc7') ON CONFLICT (id) DO NOTHING;
INSERT INTO goals (id, tenant_id, title, description, state, target_date, parent_goal_id, altitude, created_by_event_id) VALUES ('541ecca6-012a-5bf9-a8f1-a0c789279b36', '00000000-0000-0000-0000-000000000000', 'Hire VP Eng successor', 'Open after Tom''s departure (m5). Needed before Q4 to unblock the forecast model release.', 'active', '2027-01-01T13:11:52.017589+00:00', NULL, 'operational', '00000000-0000-7d24-8000-000034c17fc7') ON CONFLICT (id) DO NOTHING;
INSERT INTO decisions (id, tenant_id, title, decision_text, rationale, state, scope, revisit_triggers, created_by_event_id) VALUES ('f68dc397-12ab-5045-b52f-19325b6b7c33', '00000000-0000-0000-0000-000000000000', 'Build CRM connectors in-house vs partner', 'We''ll build the Salesforce/HubSpot/Pipedrive connectors in-house rather than partner with Workato/Tray.', 'Owning the ingest layer is core to our data quality story. Partner adds latency and limits what we can do for design partners.', 'active', '{"company_id": "pelago"}'::jsonb, '[]'::jsonb, '00000000-0000-7d24-8000-000034c17fc7') ON CONFLICT (id) DO NOTHING;
INSERT INTO decisions (id, tenant_id, title, decision_text, rationale, state, scope, revisit_triggers, created_by_event_id) VALUES ('8d38c910-ddf9-5aaa-a275-1ef3393e9be2', '00000000-0000-0000-0000-000000000000', 'Roll out conversation-AI before ICP scoring', 'Conversation-AI v1 ships ahead of ICP scoring. ICP scoring stays in research.', 'Conversation-AI is a clearer wedge for design partners. ICP scoring is a longer model-build cycle.', 'active', '{"company_id": "pelago"}'::jsonb, '[]'::jsonb, '00000000-0000-7d24-8000-000034c17fc7') ON CONFLICT (id) DO NOTHING;
INSERT INTO decisions (id, tenant_id, title, decision_text, rationale, state, scope, revisit_triggers, created_by_event_id) VALUES ('da4b1e77-b647-5b0d-85ad-41db19346488', '00000000-0000-0000-0000-000000000000', 'Adopt Snowflake as data lake (over BigQuery)', 'Snowflake replaces our BigQuery dual-writes. Migration completes Q2.', 'Snowflake''s cost model is better for our usage shape; design partners are already on Snowflake.', 'active', '{"company_id": "pelago"}'::jsonb, '[]'::jsonb, '00000000-0000-7d24-8000-000034c17fc7') ON CONFLICT (id) DO NOTHING;
INSERT INTO decisions (id, tenant_id, title, decision_text, rationale, state, scope, revisit_triggers, created_by_event_id) VALUES ('9dc69356-5187-5146-baaf-f86adfddfc3c', '00000000-0000-0000-0000-000000000000', 'Open a UK-based AE seat', 'First non-US AE; remote, London-based.', 'European pipeline has been growing organically; we need a local time zone for late-stage demos.', 'active', '{"company_id": "pelago"}'::jsonb, '[]'::jsonb, '00000000-0000-7d24-8000-000034c17fc7') ON CONFLICT (id) DO NOTHING;
INSERT INTO decisions (id, tenant_id, title, decision_text, rationale, state, scope, revisit_triggers, created_by_event_id) VALUES ('e366d260-bf12-5b7e-940c-67ac84001fb4', '00000000-0000-0000-0000-000000000000', 'Usage-based vs seat-based pricing for new tier', 'Stay with seat-based for Q1; revisit usage-based at the post-Series B board.', 'Usage-based pricing creates renewal risk for our smaller mid-market accounts; seat-based predictable for now.', 'active', '{"company_id": "pelago"}'::jsonb, '[]'::jsonb, '00000000-0000-7d24-8000-000034c17fc7') ON CONFLICT (id) DO NOTHING;
